const task = $('Build Agent Prompts').first().json;
const patch = $('Check Code Agent Output').first().json.patch_diff || '';
const changedFiles = $('Check Code Agent Output').first().json.changed_files || [];
const now = new Date();
const stamp = now.toISOString().replace(/[:.]/g, '-');
const taskId = String(task.task_id || ('task-' + Date.now()));
const patchB64 = Buffer.from(String(patch), 'utf8').toString('base64');
return [{ json: {
  task_id: taskId,
  workspace_path: task.workspace_path || '/opt/homebrew/var/www/TKIF_scholarship',
  changed_files: changedFiles,
  patch_b64: patchB64,
  apply_stamp: stamp
} }];

