let verify = {};
try {
  verify = JSON.parse($json.stdout || '{}');
} catch (e) {
  verify = { verify_ok: false, parse_error: String(e) };
}
const apply = $('Parse Apply Result').first().json || {};
const changedRaw = String(verify.changed || '').trim();
const changedFiles = changedRaw ? changedRaw.split(/\s+/).filter(Boolean) : [];
const criticalPatterns = [/public\/index\.php$/, /sql\//, /app\/lib\/profile\.php$/];
const hasCritical = changedFiles.some((f) => criticalPatterns.some((rx) => rx.test(f)));
const checklist = [
  { id: 'db-backup', title: 'Confirm latest DB backup exists and restore tested', required: hasCritical },
  { id: 'rollback-ready', title: 'Verify rollback patch path and apply audit log are present', required: true },
  { id: 'smoke-plan', title: 'Run post-deploy smoke tests for dashboard role views', required: true },
  { id: 'rbac-check', title: 'Validate IT/Admin/Manager/Student role separation post-release', required: true },
  { id: 'migration-window', title: 'Schedule migration/deploy window with owner approval', required: hasCritical },
  { id: 'monitoring', title: 'Enable monitoring and error watch for first 30 minutes', required: true }
];
return [{ json: { ...apply, verify, changed_files: changedFiles, critical_change_detected: hasCritical, release_checklist: checklist } }];

const hook = $('Run App Deploy Hook').first().json || {};
const base = hook.result || {};
const taskId = String(base.task_id || $('Build Release Checklist').first().json.task_id || ('task-' + Date.now()));
const changed = $('Build Release Checklist').first().json.changed_files || [];
const checklist = $('Build Release Checklist').first().json.release_checklist || [];
return [{ json: {
  task_id: taskId + '-monitor',
  source_task_id: taskId,
  changed_files: changed,
  checklist,
  monitoring_window_minutes: 30,
  release_notes: 'Post-release watch enabled for role dashboards and submission flow.'
} }];
